// ===== CONFIG — map YOUR sheet's column headers here (exact header text) =====
const COL = {
  email:        'Email',
  full_name:    'Name',
  phone:        'Phone',
  city:         'City',
  product:      'Product',        // FFM / FC / FW  (optional — defaults to FFM)
  payment:      'Payment Status', // the column your team / Razorpay updates
  edition_id:   'Edition Id',      // optional — assigns to an existing edition
  edition_name: 'Edition',         // optional — enables auto-create of a NEW edition
  edition_city: 'Edition City',    // required (with name+cohort) for auto-create
  cohort_type:  'Cohort Type',     // FORGE | FORGE_CREATORS | FORGE_WRITING
};
// Substrings (lowercase) in the payment column that mean each state:
const BALANCE_PAID_VALUES  = ['balance paid', 'full paid', 'paid 50', '50000', 'completed'];
const CONFIRMED_15K_VALUES = ['15k', 'deposit paid', 'confirmed', '15000', 'slot confirmed'];
const DEFERRED_VALUES      = ['defer', 'waitlist', 'postpone'];
// ============================================================================

// The HTTP node returns the CSV as a single text body on the first item.
const body = $input.first().json.data ?? $input.first().json.body ?? $input.first().binary?.data ?? '';
const text = typeof body === 'string' ? body : '';

// --- CSV parse (handles quotes) ---
function parseCSV(t) {
  const rows = []; let row = [], cell = '', q = false;
  for (let i = 0; i < t.length; i++) {
    const c = t[i], n = t[i + 1];
    if (q) {
      if (c === '"' && n === '"') { cell += '"'; i++; }
      else if (c === '"') q = false;
      else cell += c;
    } else if (c === '"') q = true;
    else if (c === ',') { row.push(cell.trim()); cell = ''; }
    else if (c === '\n' || (c === '\r' && n === '\n')) { if (c === '\r') i++; row.push(cell.trim()); cell = ''; if (row.some(x => x !== '')) rows.push(row); row = []; }
    else cell += c;
  }
  if (cell || row.length) { row.push(cell.trim()); if (row.some(x => x !== '')) rows.push(row); }
  return rows;
}

const parsed = parseCSV(text);
if (parsed.length < 2) return [];
const headers = parsed[0];
const idx = (name) => headers.findIndex(h => h.trim().toLowerCase() === (name || '').trim().toLowerCase());
const get = (r, name) => { const i = idx(name); return i >= 0 ? (r[i] || '') : ''; };
const norm = (s) => (s || '').toString().trim().toLowerCase();

const out = [];
for (let i = 1; i < parsed.length; i++) {
  const r = parsed[i];
  const email = norm(get(r, COL.email));
  if (!email || !email.includes('@')) continue;

  const payRaw = norm(get(r, COL.payment));
  let payment_status = null;
  if (BALANCE_PAID_VALUES.some(v => payRaw.includes(v)))       payment_status = 'BALANCE_PAID';
  else if (CONFIRMED_15K_VALUES.some(v => payRaw.includes(v))) payment_status = 'CONFIRMED_15K';
  else if (DEFERRED_VALUES.some(v => payRaw.includes(v)))      payment_status = 'DEFERRED';
  if (!payment_status) continue; // unrecognised payment state → ignore row

  const json = {
    student_id:  email,
    email,
    full_name:   get(r, COL.full_name),
    phone:       get(r, COL.phone),
    city:        get(r, COL.city),
    product:     (get(r, COL.product) || 'FFM').toUpperCase(),
    payment_status,
    edition_id:   get(r, COL.edition_id) || undefined,
    edition_name: get(r, COL.edition_name) || undefined,
    edition_city: get(r, COL.edition_city) || undefined,
    cohort_type:  (get(r, COL.cohort_type) || '').toUpperCase() || undefined,
  };
  // Confirmed/Balance rows are onboardable; DEFERRED is Phase-2 (waitlist) — skipped for now.
  json._onboardable = payment_status === 'CONFIRMED_15K' || payment_status === 'BALANCE_PAID';
  out.push({ json });
}
return out;

// Surface onboarding failures in the n8n execution log so they are not silent.
for (const item of $input.all()) {
  console.warn('[forge-onboard] FAILED for', item.json.email, '→', JSON.stringify(item.json));
}
return $input.all();
